// --- Utility Function to Run Shell Commands ---
async function runCommand(command, args = [], options = {}) {
  console.log(`\n>>> Executing: ${command} ${args.join(' ')}`);
  return new Promise((resolve, reject) => {
    // Use spawn for long-running commands to stream output in real-time
    // and provide better error handling than execSync.
    const child = spawn(command, args, {
      stdio: 'inherit', // Pipe child process stdio to parent process
      shell: true,      // Use system shell to interpret the command
      ...options,
    });

    child.on('close', (code) => {
      if (code === 0) {
        resolve();
      } else {
        reject(new Error(`Command failed with exit code ${code}: ${command} ${args.join(' ')}`));
      }
    });

    child.on('error', (err) => {
      reject(new Error(`Failed to start command: ${command}\nError: ${err.message}`));
    });
  });
}

